    <select id="findByUsernameAndPhone" resultType="com.example.springboot.entity.User">
        SELECT * FROM user WHERE username = #{username} AND phone = #{phone}
    </select>

    <update id="updatePassword">
        UPDATE user SET password = #{newPassword} WHERE username = #{username}
    </update>

    <select id="findById" resultType="com.example.springboot.entity.User">
        SELECT * FROM user WHERE id = #{id}
