<script setup>
import { ref } from 'vue'
import { useRouter } from 'vue-router'

const username = ref('')
const password = ref('')
const router = useRouter()

const handleLogin = async () => {
  if (username.value.length !== 6 || password.value.length !== 8) {
    alert('请输入6位用户名和8位密码')
    return
  }

  const url = `http://localhost:8080/user/login?username=${username.value}&password=${password.value}`

  try {
    const res = await fetch(url, { method: 'POST' })
    const data = await res.json()  // 解析 JSON 响应

    if (data.code === 200) {
      // 登录成功，保存 userId
      localStorage.setItem('userId', data.data.id)
      alert(data.message)
      // 保存用户名（重点，没有这个admin页面进不去）
      localStorage.setItem('username', username.value)
      // 判断是否为管理员账号
      if (username.value.toLowerCase() === 'admin1') {
        router.push('/admin/AdminFeedback'); // 跳转管理员页面
      } else {
        router.push('/')       // 跳转普通首页
      }
    } else {
      alert(data.message || '登录失败')
    }

  } catch (error) {
    alert('登录请求失败')
    console.error(error)
  }
}
</script>

















