<script setup>
import { reactive } from 'vue'
import { useRouter } from 'vue-router'

const router = useRouter()

const form = reactive({
  username: '',
  phone: '',
  password: '',
  confirmPassword: ''
})

const handleRegister = async () => {
  const usernameLower = form.username.toLowerCase()

  // 禁止包含 admin 相关用户名
  if (usernameLower === 'admin' || /^admin\d*$/.test(usernameLower)) {
    alert('禁止注册管理员相关用户名')
    return
  }
  // 基本表单校验
  if (form.username.length !== 6) {
    alert('用户名必须是6位')
    return
  }
  if (form.phone.length !== 11 || !/^\d{11}$/.test(form.phone)) {
    alert('请输入11位手机号')
    return
  }
  if (form.password.length !== 8) {
    alert('密码必须是8位')
    return
  }
  if (form.password !== form.confirmPassword) {
    alert('两次输入的密码不一致')
    return
  }

  // 发起注册请求
  try {
    const res = await fetch('http://localhost:8080/user/register', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        username: form.username,
        password: form.password,
        phone: form.phone
      })
    })

    const text = await res.text()
    alert(text)

    if (text === '注册成功') {
      router.push('/login')
    }
  } catch (error) {
    console.error('注册失败:', error)
    alert('注册请求失败，请稍后再试')
  }
}
</script>




