const handleResetPassword = async () => {
  const newPassword = prompt('请输入新的8位密码：')
  if (!newPassword || newPassword.length !== 8) {
    alert('密码长度必须为8位')
    return
  }

  const url = `http://localhost:8080/user/reset-password?username=${username.value}&phone=${phone.value}&newPassword=${newPassword}`

  try {
    const res = await fetch(url, { method: 'POST' })
    const text = await res.text()
