@RestController
@RequestMapping("/user")
public class UserController {

    @Resource
    private UserService userService;

    @PostMapping("/register")
    public String register(@RequestBody User user) {
        return userService.register(user);
    }

    @PostMapping("/login")
    public Map<String, Object> login(@RequestParam String username, @RequestParam String password) {
        Map<String, Object> result = new HashMap<>();
        User user = userService.getByUsername(username);
        if (user != null && userService.verifyPassword(password, user.getPassword())) {
            result.put("code", 200);
            result.put("message", "登录成功");
            result.put("data", Map.of(
                    "id", user.getId(),
                    "name", user.getUsername()
            ));
        } else {
            result.put("code", 401);
            result.put("message", "用户名或密码错误");
        }
        return result;
    }


    @PostMapping("/reset-password")
    public String resetPassword(@RequestParam String username,
                                @RequestParam String phone,
                                @RequestParam String newPassword) {
        return userService.resetPassword(username, phone, newPassword);
    }
    @GetMapping("/info")
    public Map<String, Object> getUserInfo(@RequestParam Integer id) {
        User user = userService.getById(id);
        Map<String, Object> result = new HashMap<>();
        if (user != null) {
            result.put("name", user.getUsername());
        } else {
            result.put("name", "未知用户");
        }
        return result;
    }
