    return
  }

  const url = `http://localhost:8080/user/login?username=${username.value}&password=${password.value}`

  try {
    const res = await fetch(url, { method: 'POST' })
    const data = await res.json()  // 解析 JSON 响应

    if (data.code === 200) {
      // 登录成功，保存 userId
